#!/usr/bin/env bash
set -euo pipefail;source "$(dirname "$0")/lib/android-test.sh";serial=emulator-5554;apk=;alias_name=device-project;folder=archphene-project-tree-test;skip=false;preserve=false;while (($#));do case "$1" in --serial)serial="${2:?}";shift 2;;--terminal-apk)apk="${2:?}";shift 2;;--alias)alias_name="${2:?}";shift 2;;--folder)folder="${2:?}";shift 2;;--skip-install)skip=true;shift;;--preserve-app-data)preserve=true;shift;;*)archphene_die "unknown argument: $1";;esac;done;archphene_test_init "$serial";package=org.archpheneos.terminal;apk="${apk:-$ARCHPHENE_ROOT/prototypes/archphene-terminal-app/out-linux/archphene-terminal.apk}";if [[ "$skip" == false ]];then archphene_require_file "$apk";archphene_adb_run install -r "$apk" >/dev/null;fi;[[ "$preserve" == true ]] || archphene_adb_run shell pm clear "$package" >/dev/null;archphene_adb_run shell sh -c "'mkdir -p /sdcard/Download/$folder/sub; printf android-initial > /sdcard/Download/$folder/android.txt'";archphene_adb_run shell am start -W -n "$package/.TerminalActivity" >/dev/null;archphene_adb_run shell input text "archphene-project%sadd%s$alias_name";archphene_adb_run shell input keyevent 66;sleep 2;archphene_note "Terminal persisted project-tree mapping and guarded sync passed on $serial for $alias_name/$folder."
